#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    if (controller == 0) {
        return;
    }
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

static bool temperature_is_rising(const controller_t *controller, int new_temperature)
{
    if (controller == 0 || !controller->has_valid_sensor) {
        return false;
    }
    return new_temperature > controller->last_temperature_c;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Handle sensor timeout - fail safe */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller_set_safe_off(controller);
        output.timed_out = true;
        goto return_output;
    }

    /* Handle invalid temperature - fail safe */
    if (input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
        controller_set_safe_off(controller);
        goto return_output;
    }

    /* Handle no input / none */
    if (input.kind == CONTROLLER_INPUT_NONE) {
        /* Check for timeout condition - no valid sensor for > 1000ms */
        if (controller->has_valid_sensor) {
            uint32_t elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
            if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
                /* Timeout - fail safe */
                controller_set_safe_off(controller);
                output.timed_out = true;
                goto return_output;
            }
        }
        /* No new input, just check timeout and return current state */
        output.heater_on = controller->heater_on;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
        return output;
    }

    /* Handle temperature input */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        int temp = input.temperature_c;

        /* Check if temperature is rising BEFORE updating state for comparison */
        bool is_rising_check = false;
        if (controller->has_valid_sensor && controller->last_temperature_c != 0) {
            is_rising_check = temp > controller->last_temperature_c;
        }

        /* Update sensor state */
        controller->has_valid_sensor = true;
        controller->last_temperature_c = temp;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Temperature is low - turn heater on */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
            output.heater_on = controller->heater_on;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
            goto return_output;
        }

        /* Temperature is above upper band - turn heater off */
        if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_SAFE_OFF;
            output.heater_on = controller->heater_on;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
            goto return_output;
        }

        /* Temperature in lower band: 47 <= TEMP < 50 */
        if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            /* Hold previous safe actuator state, update to HOLDING */
            controller->heater_on = controller->heater_on;  // preserve
            controller->state = CONTROLLER_STATE_HOLDING;   // update state
            output.heater_on = controller->heater_on;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
            goto return_output;
        }

        /* Temperature in upper band: 50 <= TEMP <= 52 */
        if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            bool is_rising = is_rising_check;

            if (is_rising) {
                /* Rising temperature - turn heater off early, state = HOLDING */
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
                output.heater_on = controller->heater_on;
                output.state = controller->state;
                output.state_name = controller_state_name(controller->state);
                output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
            } else {
                /* Not rising - hold previous safe actuator state, update to HOLDING */
                controller->heater_on = controller->heater_on;  // preserve
                controller->state = CONTROLLER_STATE_HOLDING;   // update state
                output.heater_on = controller->heater_on;
                output.state = controller->state;
                output.state_name = controller_state_name(controller->state);
                output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
            }
            goto return_output;
        }

        /* Default - should not reach here for valid temperatures */
        controller_set_safe_off(controller);
        output.timed_out = true;
        goto return_output;
    }

return_output:
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}
